1	import { type ClassValue, clsx } from "clsx";
2	import { twMerge } from "tailwind-merge";
3	
4	export function cn(...inputs: ClassValue[]) {
5	  return twMerge(clsx(inputs));
6	}
7	
8	export function formatDate(date: Date | string): string {
9	  return new Date(date).toLocaleDateString("zh-CN", {
10	    year: "numeric",
11	    month: "long",
12	    day: "numeric",
13	    weekday: "long",
14	  });
15	}
16	
17	export function getToday(): string {
18	  return new Date().toISOString().split("T")[0];
19	}
20	
21	export function getStreak(dates: string[]): number {
22	  const sorted = [...dates].sort().reverse();
23	  let streak = 0;
24	  const today = new Date(getToday());
25	  for (let i = 0; i < sorted.length; i++) {
26	    const expected = new Date(today);
27	    expected.setDate(expected.getDate() - i);
28	    if (sorted[i] === expected.toISOString().split("T")[0]) {
29	      streak++;
30	    } else {
31	      break;
32	    }
33	  }
34	  return streak;
35	}
