1	"use client";
2	
3	import { useState, useEffect } from "react";
4	import { formatDate, getToday, PRESET_DOMAINS } from "@/lib/utils";
5	import { apiFetch } from "@/lib/api";
6	import { CheckCircle2, Circle, Flame, Trophy, Target } from "lucide-react";
7	
8	interface Habit {
9	  id: string;
10	  title: string;
11	  description: string | null;
12	  domainId: string;
13	  unit: string;
14	  targetValue: number;
15	  isActive: boolean;
16	  logs?: { date: string; completed: boolean; value: number }[];
17	}
18	
19	export default function DashboardPage() {
20	  const [habits, setHabits] = useState<Habit[]>([]);
21	  const [loading, setLoading] = useState(true);
22	
23	  useEffect(() => {
24	    fetchHabits();
25	  }, []);
26	
27	  async function fetchHabits() {
28	    const data = await apiFetch("/api/habits?date=" + getToday());
29	    setHabits(data);
30	    setLoading(false);
31	  }
32	
33	  async function toggleHabit(habitId: string) {
34	    await apiFetch("/api/logs", {
35	      method: "POST",
36	      body: JSON.stringify({ habitId, date: getToday() }),
37	    });
38	    fetchHabits();
39	  }
40	
41	  const completedCount = habits.filter(
42	    (h) => h.logs?.length && h.logs[0]?.completed
43	  ).length;
44	  const totalCount = habits.filter((h) => h.isActive).length;
45	  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
46	
47	  if (loading) {
48	    return (
49	      <div className="flex items-center justify-center h-64 text-muted-foreground">
50	        加载中...
51	      </div>
52	    );
53	  }
54	
55	  return (
56	    <div className="max-w-2xl mx-auto space-y-6">
57	      {/* Header */}
58	      <div>
59	        <p className="text-sm text-muted-foreground">{formatDate(new Date())}</p>
60	        <h1 className="text-3xl font-bold mt-1 tracking-tight">今日日课</h1>
61	      </div>
62	
63	      {/* Progress Ring */}
64	      <div className="bg-card rounded-2xl border p-6 flex items-center gap-6">
65	        <div className="relative w-20 h-20 flex-shrink-0">
66	          <svg className="w-20 h-20 -rotate-90" viewBox="0 0 80 80">
67	            <circle cx="40" cy="40" r="34" fill="none" stroke="var(--border)" strokeWidth="6" />
68	            <circle
69	              cx="40" cy="40" r="34"
70	              fill="none" stroke="var(--primary)" strokeWidth="6"
71	              strokeLinecap="round"
72	              strokeDasharray={`${progressPct * 2.14} 214`}
73	            />
74	          </svg>
75	          <span className="absolute inset-0 flex items-center justify-center text-lg font-bold">
76	            {progressPct}%
77	          </span>
78	        </div>
79	        <div>
80	          <p className="text-2xl font-bold">{completedCount}/{totalCount}</p>
81	          <p className="text-sm text-muted-foreground">今日已完成</p>
82	          <div className="flex gap-2 mt-1 text-xs text-muted-foreground">
83	            <span className="flex items-center gap-1"><Flame className="w-3 h-3 text-orange-500" /> 连续 0 天</span>
84	          </div>
85	        </div>
86	      </div>
87	
88	      {/* Habit List grouped by domain */}
89	      {PRESET_DOMAINS.map((domain) => {
90	        const domainHabits = habits.filter((h) => h.domainId === domain.name && h.isActive);
91	        if (domainHabits.length === 0) return null;
92	        return (
93	          <div key={domain.name}>
94	            <h2 className="text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
95	              <span>{domain.icon}</span> {domain.name}
96	            </h2>
97	            <div className="space-y-1">
98	              {domainHabits.map((habit) => {
99	                const done = habit.logs?.length && habit.logs[0]?.completed;
100	                return (
101	                  <button
102	                    key={habit.id}
103	                    onClick={() => toggleHabit(habit.id)}
104	                    className={`w-full flex items-center gap-3 p-4 rounded-xl border transition-all text-left ${
105	                      done
106	                        ? "bg-muted border-border opacity-60"
107	                        : "bg-card hover:border-primary/30 hover:shadow-sm"
108	                    }`}
109	                  >
110	                    {done ? (
111	                      <CheckCircle2 className="w-6 h-6 text-success flex-shrink-0" />
112	                    ) : (
113	                      <Circle className="w-6 h-6 text-muted-foreground flex-shrink-0" />
114	                    )}
115	                    <div className="flex-1 min-w-0">
116	                      <p className={`font-medium ${done ? "line-through text-muted-foreground" : ""}`}>
117	                        {habit.title}
118	                      </p>
119	                      {habit.description && (
120	                        <p className="text-xs text-muted-foreground truncate">{habit.description}</p>
121	                      )}
122	                    </div>
123	                    <span className="text-xs text-muted-foreground">
124	                      {habit.targetValue}{habit.unit}
125	                    </span>
126	                  </button>
127	                );
128	              })}
129	            </div>
130	          </div>
131	        );
132	      })}
133	
134	      {totalCount === 0 && (
135	        <div className="text-center py-12 text-muted-foreground">
136	          <Target className="w-12 h-12 mx-auto mb-3 opacity-30" />
137	          <p>还没有习惯</p>
138	          <p className="text-sm mt-1">去「习惯」页面添加你的第一个日课吧</p>
139	        </div>
140	      )}
141	    </div>
142	  );
143	}
