import * as React from "react";
import { cn } from "@/lib/utils";
import { X } from "lucide-react";

interface SheetContextType {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

const SheetContext = React.createContext<SheetContextType>({
  open: false,
  onOpenChange: () => {},
});

function Sheet({ children, open: controlledOpen, onOpenChange }: {
  children: React.ReactNode;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}) {
  const [internalOpen, setInternalOpen] = React.useState(false);
  const open = controlledOpen ?? internalOpen;
  const setOpen = onOpenChange ?? setInternalOpen;

  return (
    <SheetContext.Provider value={{ open, onOpenChange: setOpen }}>
      {children}
    </SheetContext.Provider>
  );
}

function SheetTrigger({ children, asChild, onClick }: {
  children: React.ReactNode;
  asChild?: boolean;
  onClick?: () => void;
}) {
  const { onOpenChange } = React.useContext(SheetContext);
  return (
    <button
      type="button"
      onClick={() => {
        onOpenChange(true);
        onClick?.();
      }}
      className={cn(asChild ? "" : "inline-flex items-center justify-center")}
    >
      {children}
    </button>
  );
}

function SheetContent({ children, className, side = "left" }: {
  children: React.ReactNode;
  className?: string;
  side?: "left" | "right" | "top" | "bottom";
}) {
  const { open, onOpenChange } = React.useContext(SheetContext);
  const [visible, setVisible] = React.useState(open);

  React.useEffect(() => {
    if (open) {
      setVisible(true);
    } else {
      const timer = setTimeout(() => setVisible(false), 200);
      return () => clearTimeout(timer);
    }
  }, [open]);

  if (!visible && !open) return null;

  return (
    <>
      {/* Overlay */}
      <div
        className={cn(
          "fixed inset-0 z-50 bg-black/50 transition-opacity duration-200",
          open ? "opacity-100" : "opacity-0 pointer-events-none"
        )}
        onClick={() => onOpenChange(false)}
      />
      {/* Panel */}
      <div
        className={cn(
          "fixed z-50 gap-4 bg-card p-6 shadow-lg transition-transform duration-200",
          side === "left" && "inset-y-0 left-0 h-full w-72 max-w-[80vw]",
          side === "right" && "inset-y-0 right-0 h-full w-72 max-w-[80vw]",
          side === "top" && "inset-x-0 top-0 h-auto",
          side === "bottom" && "inset-x-0 bottom-0 h-auto",
          open
            ? "translate-x-0 translate-y-0"
            : side === "left"
            ? "-translate-x-full"
            : side === "right"
            ? "translate-x-full"
            : side === "top"
            ? "-translate-y-full"
            : "translate-y-full",
          className
        )}
      >
        <button
          onClick={() => onOpenChange(false)}
          className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100"
        >
          <X className="h-4 w-4" />
          <span className="sr-only">Close</span>
        </button>
        {children}
      </div>
    </>
  );
}

function SheetHeader({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div className={cn("flex flex-col space-y-2 text-center sm:text-left mb-6", className)} {...props} />
  );
}

function SheetTitle({ className, ...props }: React.HTMLAttributes<HTMLHeadingElement>) {
  return <h2 className={cn("text-lg font-semibold text-foreground", className)} {...props} />;
}

export { Sheet, SheetTrigger, SheetContent, SheetHeader, SheetTitle };

