    setUser((prev) => ({ ...prev, role, name: names[role] }));
  }, []);

  return (
    <AuthContext.Provider value={{ user, setRole, unreadNotifications, setUnreadNotifications }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}

