  Laptop,
  ClipboardPlus,
  Ticket,
  Bot,
  Bell,
  Settings,
  CheckSquare,
  BarChart3,
  Wrench,
  Package,
  Archive,
  Boxes,
  ClipboardList,
  Users,
  FileText,
  PieChart,
  Lightbulb,
  ChevronDown,
} from "lucide-react";

type NavItem = {
  label: string;
  href: string;
  icon: React.ElementType;
  roles: UserRole[];
  children?: NavItem[];
};

const navItems: NavItem[] = [
  { label: "首页", href: "/home", icon: LayoutDashboard, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
  { label: "我的资产", href: "/my-assets", icon: Laptop, roles: ["EMPLOYEE", "MANAGER"] },
  { label: "申领设备", href: "/apply", icon: ClipboardPlus, roles: ["EMPLOYEE", "MANAGER"] },
  { label: "我的工单", href: "/tickets", icon: Ticket, roles: ["EMPLOYEE", "MANAGER"] },
  { label: "AI 助手", href: "/chat", icon: Bot, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
  { label: "通知中心", href: "/notifications", icon: Bell, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
  { label: "个人设置", href: "/profile", icon: Settings, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },

  // MANAGER
  { label: "审批工作台", href: "/approvals", icon: CheckSquare, roles: ["MANAGER"] },
  { label: "部门看板", href: "/dept-board", icon: BarChart3, roles: ["MANAGER"] },

  // IT_ADMIN
  { label: "IT 工作台", href: "/it/home", icon: Wrench, roles: ["IT_ADMIN"] },
  { label: "工单工作台", href: "/it/tickets", icon: Ticket, roles: ["IT_ADMIN"] },
  { label: "资产管理", href: "/it/assets", icon: Package, roles: ["IT_ADMIN"] },
  { label: "型号管理", href: "/it/models", icon: Archive, roles: ["IT_ADMIN"] },
  { label: "入库操作", href: "/it/inbound", icon: Boxes, roles: ["IT_ADMIN"] },
  { label: "盘点", href: "/it/inventory", icon: ClipboardList, roles: ["IT_ADMIN"] },
  { label: "用户管理", href: "/it/users", icon: Users, roles: ["IT_ADMIN"] },
  { label: "审计日志", href: "/it/audit", icon: FileText, roles: ["IT_ADMIN"] },

  // EXECUTIVE
  { label: "资产大屏", href: "/exec/dashboard", icon: PieChart, roles: ["EXECUTIVE"] },
  { label: "AI 洞察", href: "/exec/insights", icon: Lightbulb, roles: ["EXECUTIVE"] },
];

function filterNavItems(items: NavItem[], role: UserRole): NavItem[] {
  return items.filter((item) => item.roles.includes(role));
}

interface SidebarProps {
  collapsed?: boolean;
  onNavigate?: () => void;
}

export default function Sidebar({ collapsed, onNavigate }: SidebarProps) {
  const pathname = usePathname();
  const { user } = useAuth();
  const filteredItems = filterNavItems(navItems, user.role);

  const isActive = (href: string) => {
    if (href === "/home") return pathname === "/home";
    return pathname.startsWith(href);
  };

  return (
    <div className="flex flex-col h-full">
      {/* Logo / Brand */}
      <div className={cn("px-4 py-5 border-b border-sidebar-accent", collapsed && "px-2")}>
        <h1 className={cn(
          "text-lg font-bold text-white tracking-tight",
          collapsed && "text-center text-sm"
        )}>
          {collapsed ? "IT" : "资产管理系统"}
        </h1>
        {!collapsed && (
          <p className="text-xs text-sidebar-muted mt-0.5">
            {user.department} · {user.name}
          </p>
        )}
      </div>

      {/* Navigation */}
      <nav className="flex-1 overflow-y-auto py-2 px-2 space-y-0.5">
        {filteredItems.map((item) => (
          <Link
            key={item.href}
            href={item.href}
            onClick={onNavigate}
            className={cn(
              "flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors",
              isActive(item.href)
                ? "bg-primary text-primary-foreground"
                : "text-sidebar-fg hover:bg-sidebar-accent hover:text-white",
              collapsed && "justify-center px-2"
            )}
            title={collapsed ? item.label : undefined}
          >
            <item.icon className="w-5 h-5 flex-shrink-0" />
            {!collapsed && <span>{item.label}</span>}
          </Link>
        ))}
      </nav>

      {/* Role Switcher (Dev tool) */}
      {!collapsed && (
        <div className="px-3 py-3 border-t border-sidebar-accent">
          <RoleSwitcher />
        </div>
      )}
    </div>
  );
}

function RoleSwitcher() {
  const { user, setRole } = useAuth();
  const [open, setOpen] = React.useState(false);

  const roles: { value: UserRole; label: string }[] = [
    { value: "EMPLOYEE", label: "员工" },
    { value: "MANAGER", label: "主管" },
    { value: "IT_ADMIN", label: "IT管理员" },
    { value: "EXECUTIVE", label: "管理层" },
  ];

  return (
    <div className="relative">
      <button
        onClick={() => setOpen(!open)}
        className="flex items-center justify-between w-full px-2 py-1.5 text-xs text-sidebar-muted hover:text-sidebar-fg rounded-md hover:bg-sidebar-accent transition-colors"
      >
        <span>调试: {roles.find((r) => r.value === user.role)?.label}</span>
        <ChevronDown className="w-3 h-3" />
      </button>
      {open && (
        <div className="absolute bottom-full left-0 right-0 mb-1 bg-sidebar rounded-lg border border-sidebar-accent shadow-lg overflow-hidden">
          {roles.map((r) => (
            <button
              key={r.value}
              onClick={() => {
                setRole(r.value);
                setOpen(false);
              }}
              className={cn(
                "w-full text-left px-3 py-2 text-xs transition-colors",
                user.role === r.value
                  ? "bg-primary text-primary-foreground"
                  : "text-sidebar-fg hover:bg-sidebar-accent"
              )}
            >
              {r.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

