import Sidebar from "./sidebar";
import Header from "./header";
import { Sheet, SheetContent } from "@/components/ui/sheet";

export default function AppLayout({ children }: { children: React.ReactNode }) {
  const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);

  return (
    <div className="flex h-screen overflow-hidden">
      {/* Desktop Sidebar */}
      <aside className="hidden md:flex md:w-60 lg:w-64 flex-col bg-sidebar text-sidebar-fg flex-shrink-0">
        <Sidebar />
      </aside>

      {/* Mobile Sidebar (Sheet) */}
      <Sheet open={mobileSidebarOpen} onOpenChange={setMobileSidebarOpen}>
        <SheetContent side="left" className="bg-sidebar text-sidebar-fg p-0 border-r border-sidebar-accent">
          <Sidebar onNavigate={() => setMobileSidebarOpen(false)} />
        </SheetContent>
      </Sheet>

      {/* Main area */}
      <div className="flex flex-col flex-1 min-w-0">
        <Header onMenuClick={() => setMobileSidebarOpen(true)} />
        <main className="flex-1 overflow-auto p-4 md:p-6 lg:p-8">
          {children}
        </main>
      </div>
    </div>
  );
}

import { Badge } from "@/components/ui/badge";

type AssetStatus =
  | "IN_STOCK"
  | "AVAILABLE"
  | "ASSIGNED"
  | "IN_USE"
  | "RETURNING"
  | "REPAIRING"
  | "TRANSFERRING"
  | "LOST"
  | "SCRAPPED";

const statusConfig: Record<AssetStatus, { label: string; variant: "green" | "blue" | "orange" | "red" | "gray" | "purple" }> = {
  IN_STOCK: { label: "在库", variant: "gray" },
  AVAILABLE: { label: "可用", variant: "green" },
  ASSIGNED: { label: "已分配", variant: "blue" },
  IN_USE: { label: "使用中", variant: "blue" },
  RETURNING: { label: "归还中", variant: "orange" },
  REPAIRING: { label: "维修中", variant: "orange" },
  TRANSFERRING: { label: "调拨中", variant: "purple" },
  LOST: { label: "丢失", variant: "red" },
  SCRAPPED: { label: "已报废", variant: "red" },
};

export default function AssetStatusBadge({ status }: { status: AssetStatus }) {
  const config = statusConfig[status];
  if (!config) {
    return <Badge variant="gray">{status}</Badge>;
  }
  return <Badge variant={config.variant}>{config.label}</Badge>;
}

export type { AssetStatus };

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { Inbox } from "lucide-react";

interface EmptyStateProps {
  icon?: React.ElementType;
  title: string;
  description?: string;
  actionLabel?: string;
  onAction?: () => void;
  actionHref?: string;
  className?: string;
}

export default function EmptyState({
  icon: Icon = Inbox,
  title,
  description,
  actionLabel,
  onAction,
  actionHref,
  className,
}: EmptyStateProps) {
  const ActionButton = () => {
    if (!actionLabel) return null;
    return (
      <Button onClick={onAction} asChild={!!actionHref}>
        {actionHref ? (
          <a href={actionHref}>{actionLabel}</a>
        ) : (
          <>{actionLabel}</>
        )}
      </Button>
    );
  };

  return (
    <div className={cn(
      "flex flex-col items-center justify-center py-16 px-4 text-center",
      className
    )}>
      <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mb-4">
        <Icon className="w-8 h-8 text-muted-foreground" />
      </div>
      <h3 className="text-lg font-semibold text-foreground mb-1">{title}</h3>
      {description && (
        <p className="text-sm text-muted-foreground max-w-sm mb-6">{description}</p>
      )}
      <ActionButton />
    </div>
  );
}

"use client";

import { useAuth, type UserRole } from "@/lib/auth-context";

interface RoleGuardProps {
  roles: UserRole[];
  children: React.ReactNode;
  fallback?: React.ReactNode;
}

export default function RoleGuard({ roles, children, fallback = null }: RoleGuardProps) {
  const { user } = useAuth();
  if (roles.includes(user.role)) {
    return <>{children}</>;
  }
  return <>{fallback}</>;
}

"use client";

import Link from "next/link";
import { Bell } from "lucide-react";
import { useAuth } from "@/lib/auth-context";

export default function NotificationBell() {
  const { unreadNotifications } = useAuth();

  return (
    <Link
      href="/notifications"
      className="relative inline-flex items-center justify-center rounded-lg p-2 text-muted-foreground hover:bg-muted hover:text-foreground transition-colors"
    >
      <Bell className="w-5 h-5" />
      {unreadNotifications > 0 && (
        <span className="absolute -top-0.5 -right-0.5 flex h-4 w-4 min-w-4 items-center justify-center rounded-full bg-destructive text-[10px] font-bold text-white">
          {unreadNotifications > 9 ? "9+" : unreadNotifications}
        </span>
      )}
    </Link>
  );
}

import { cn } from "@/lib/utils";
import { CheckCircle2, Circle, Clock, XCircle } from "lucide-react";

type TimelineEventStatus = "completed" | "current" | "pending" | "rejected" | "cancelled";

interface TimelineEvent {
  id: string;
  status: TimelineEventStatus;
  title: string;
  description?: string;
  timestamp?: string;
  actor?: string;
}

interface TicketTimelineProps {
  events: TimelineEvent[];
  className?: string;
}

const statusIcon = {
  completed: CheckCircle2,
  current: Clock,
  pending: Circle,
  rejected: XCircle,
  cancelled: XCircle,
};

const statusColors = {
  completed: "text-success",
  current: "text-primary",
  pending: "text-muted-foreground",
  rejected: "text-destructive",
  cancelled: "text-muted-foreground",
};

const lineColors = {
  completed: "bg-success",
  current: "bg-primary",
  pending: "bg-border",
  rejected: "bg-destructive",
  cancelled: "bg-border",
};

export default function TicketTimeline({ events, className }: TicketTimelineProps) {
  if (events.length === 0) {
    return (
      <div className="text-sm text-muted-foreground text-center py-8">
        暂无时间轴记录
      </div>
    );
  }

  return (
    <div className={cn("space-y-0", className)}>
      {events.map((event, index) => {
        const Icon = statusIcon[event.status];
        const isLast = index === events.length - 1;

        return (
          <div key={event.id} className="flex gap-4">
            {/* Timeline line + icon */}
            <div className="flex flex-col items-center">
              <div className={cn(
                "rounded-full p-0.5",
                statusColors[event.status]
              )}>
                <Icon className="w-5 h-5" />
              </div>
              {!isLast && (
                <div className={cn(
                  "w-0.5 flex-1 min-h-8",
                  lineColors[event.status]
                )} />
              )}
            </div>

            {/* Content */}
            <div className={cn("pb-6 flex-1", isLast && "pb-0")}>
              <p className={cn(
                "text-sm font-medium",
                event.status === "pending" && "text-muted-foreground"
              )}>
                {event.title}
              </p>
              {event.description && (
                <p className="text-sm text-muted-foreground mt-0.5">{event.description}</p>
              )}
              {(event.timestamp || event.actor) && (
                <div className="flex items-center gap-2 mt-1">
                  {event.timestamp && (
                    <span className="text-xs text-muted-foreground">{event.timestamp}</span>
                  )}
                  {event.actor && (
                    <span className="text-xs text-muted-foreground">by {event.actor}</span>
                  )}
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

export type { TimelineEvent, TimelineEventStatus };

