"use client";

/**
 * 我的资产列表 (员工/主管)
 * 功能说明: 显示当前用户持有的所有资产列表，包含空状态和跳转申领按钮
 */

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import EmptyState from "@/components/empty-state";
import AssetStatusBadge from "@/components/asset-status-badge";
import { Laptop } from "lucide-react";

const mockAssets: {
  id: string;
  name: string;
  sn: string;
  model: string;
  status: "IN_USE" | "REPAIRING" | "RETURNING";
  assignedAt: string;
}[] = [];

export default function MyAssetsPage() {
  const isLoading = false;

  if (isLoading) {
    return (
      <div className="max-w-4xl mx-auto space-y-4">
        <div className="animate-pulse space-y-4">
          {Array.from({ length: 3 }).map((_, i) => (
            <div key={i} className="h-24 bg-muted rounded-xl" />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">我的资产</h1>
        <p className="text-muted-foreground mt-1">查看你当前持有的所有设备</p>
      </div>

      {mockAssets.length === 0 ? (
        <EmptyState
          icon={Laptop}
          title="你目前没有持有任何设备"
          description="你可以去申领一台你需要的设备，或者查看可用的设备列表。"
          actionLabel="去申领设备"
          actionHref="/apply"
        />
      ) : (
        <div className="space-y-3">
          {mockAssets.map((asset) => (
            <Card key={asset.id} className="hover:shadow-md transition-shadow">
              <CardContent className="p-4 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-lg bg-muted flex items-center justify-center">
                    <Laptop className="w-5 h-5 text-muted-foreground" />
                  </div>
                  <div>
                    <p className="font-medium">{asset.name}</p>
                    <p className="text-sm text-muted-foreground">{asset.model} | SN: {asset.sn}</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <AssetStatusBadge status={asset.status} />
                  <span className="text-xs text-muted-foreground">
                    {asset.assignedAt} 分配
                  </span>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * 申领设备 (员工/主管)
 * 功能说明: 输入需求描述 → AI推荐型号 → 选择型号 → 填写理由 → 提交申领
 */

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Bot, Sparkles, Send } from "lucide-react";

export default function ApplyPage() {
  const [description, setDescription] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [recommendations, setRecommendations] = useState<{ modelId: string; name: string; specs: string; score: number; reason: string; inStock: number }[]>([]);
  const [selectedModel, setSelectedModel] = useState<string | null>(null);
  const [reason, setReason] = useState("");
  const [submitted, setSubmitted] = useState(false);

  const handleSearch = async () => {
    if (!description.trim()) return;
    setIsSearching(true);
    // Simulate AI recommendation
    setTimeout(() => {
      setRecommendations([
        { modelId: "MODEL-L01", name: "ThinkPad X1 Carbon Gen 12", specs: "CPU: i7-1370P, RAM: 32GB, SSD: 512GB", score: 0.95, reason: "高性能轻薄本，适合你的开发需求", inStock: 5 },
        { modelId: "MODEL-L02", name: "MacBook Pro 14\" M4 Pro", specs: "CPU: M4 Pro, RAM: 36GB, SSD: 1TB", score: 0.88, reason: "如果你偏好 macOS 开发环境，这是最佳选择", inStock: 3 },
        { modelId: "MODEL-M01", name: "Dell U2724D 27\" 显示器", specs: "27\", 2560x1440, USB-C Hub", score: 0.72, reason: "配合笔记本使用，提升多任务效率", inStock: 10 },
      ]);
      setIsSearching(false);
    }, 1500);
  };

  const handleSubmit = () => {
    setSubmitted(true);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">申领设备</h1>
        <p className="text-muted-foreground mt-1">描述你的需求，AI 将为你推荐最合适的设备</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Bot className="w-5 h-5 text-primary" />
            AI 智能推荐
          </CardTitle>
          <CardDescription>用自然语言描述你的工作需求，系统将自动匹配最佳设备型号</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-2">
            <Input
              placeholder="例如: 我需要一台用于前端开发的笔记本，16GB内存以上，轻薄便携..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSearch()}
              className="flex-1"
            />
            <Button onClick={handleSearch} disabled={!description.trim() || isSearching}>
              <Sparkles className="w-4 h-4 mr-1" />
              {isSearching ? "分析中..." : "AI 推荐"}
            </Button>
          </div>

          {/* Loading */}
          {isSearching && (
            <div className="space-y-3">
              {Array.from({ length: 3 }).map((_, i) => (
                <Skeleton key={i} className="h-20 rounded-lg" />
              ))}
            </div>
          )}

          {/* Recommendations */}
          {!isSearching && recommendations.length > 0 && (
            <div className="space-y-3">
              <p className="text-sm font-medium text-muted-foreground">AI 推荐结果</p>
              {recommendations.map((rec) => (
                <div
                  key={rec.modelId}
                  className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                    selectedModel === rec.modelId
                      ? "border-primary bg-secondary"
                      : "border-border hover:border-primary/50"
                  }`}
                  onClick={() => setSelectedModel(rec.modelId)}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <p className="font-medium">{rec.name}</p>
                        <Badge variant={rec.score >= 0.9 ? "success" : "blue"}>
                          匹配度 {Math.round(rec.score * 100)}%
                        </Badge>
                      </div>
                      <p className="text-sm text-muted-foreground mt-1">{rec.specs}</p>
                      <p className="text-xs text-primary mt-1">{rec.reason}</p>
                    </div>
                    <div className="text-right text-sm text-muted-foreground flex-shrink-0 ml-4">
                      <Badge variant="gray">库存 {rec.inStock}</Badge>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* No results yet */}
          {!isSearching && recommendations.length === 0 && (
            <div className="text-center py-8 text-muted-foreground">
              <Bot className="w-12 h-12 mx-auto mb-2 opacity-30" />
              <p className="text-sm">在上方输入你的工作需求，点击 AI 推荐</p>
              <p className="text-xs mt-1">系统将根据你的需求智能匹配可用设备</p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Submit Section */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">申领信息</CardTitle>
          <CardDescription>请填写申领理由，提交后将进入审批流程</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div>
            <label className="text-sm font-medium mb-1 block">
              已选型号
            </label>
            <div className="p-3 rounded-lg bg-muted text-sm">
              {selectedModel
                ? recommendations.find((r) => r.modelId === selectedModel)?.name || selectedModel
                : "请先在上方选择推荐的型号"}
            </div>
          </div>

          <div>
            <label className="text-sm font-medium mb-1 block">
              申领理由 <span className="text-destructive">*</span>
            </label>
            <Textarea
              placeholder="请详细说明你需要该设备的理由，这将帮助审批人快速了解你的需求..."
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              rows={4}
            />
          </div>

          <div className="flex justify-end">
            <Button
              onClick={handleSubmit}
              disabled={!selectedModel || !reason.trim()}
              className="w-full sm:w-auto"
            >
              <Send className="w-4 h-4 mr-1" />
              提交申领
            </Button>
          </div>

          {submitted && (
            <div className="p-4 rounded-lg bg-green-50 text-green-800 text-sm">
              申领已提交，工单编号: TKT-20260511-001。请耐心等待审批。
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

/**
 * 我的工单列表 (员工/主管)
 * 功能说明: 列出当前用户的全部工单，支持按状态和类型筛选
 */

import { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import EmptyState from "@/components/empty-state";
import { Ticket, Filter, Plus } from "lucide-react";
import Link from "next/link";

type TicketStatus = "SUBMITTED" | "PENDING_MANAGER" | "PENDING_IT" | "APPROVED" | "REJECTED" | "IN_PROGRESS" | "COMPLETED" | "CANCELLED";
type TicketType = "APPLY" | "RETURN" | "REPAIR" | "TRANSFER";

const mockTickets: { id: string; type: TicketType; status: TicketStatus; title: string; createdAt: string }[] = [];

const statusLabels: Record<TicketStatus, string> = {
  SUBMITTED: "已提交",
  PENDING_MANAGER: "待主管审批",
  PENDING_IT: "待IT处理",
  APPROVED: "已通过",
  REJECTED: "已驳回",
  IN_PROGRESS: "处理中",
  COMPLETED: "已完成",
  CANCELLED: "已取消",
};

const statusVariants: Record<TicketStatus, "blue" | "orange" | "green" | "red" | "gray" | "purple"> = {
  SUBMITTED: "blue",
  PENDING_MANAGER: "orange",
  PENDING_IT: "orange",
  APPROVED: "green",
  REJECTED: "red",
  IN_PROGRESS: "purple",
  COMPLETED: "green",
  CANCELLED: "gray",
};

const typeLabels: Record<TicketType, string> = {
  APPLY: "申领",
  RETURN: "归还",
  REPAIR: "报修",
  TRANSFER: "调拨",
};

export default function TicketsPage() {
  const [statusFilter, setStatusFilter] = useState<string>("all");

  const filtered = statusFilter === "all"
    ? mockTickets
    : mockTickets.filter((t) => t.status === statusFilter);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">我的工单</h1>
          <p className="text-muted-foreground mt-1">查看和管理你的所有工单</p>
        </div>
        <Link href="/apply">
          <Button>
            <Plus className="w-4 h-4 mr-1" />
            新建申领
          </Button>
        </Link>
      </div>

      {/* Filter tabs */}
      <div className="flex gap-2 overflow-x-auto pb-2">
        {[
          { value: "all", label: "全部" },
          { value: "PENDING_MANAGER", label: "待审批" },
          { value: "PENDING_IT", label: "待处理" },
          { value: "IN_PROGRESS", label: "处理中" },
          { value: "COMPLETED", label: "已完成" },
          { value: "REJECTED", label: "已驳回" },
        ].map((tab) => (
          <button
            key={tab.value}
            onClick={() => setStatusFilter(tab.value)}
            className={`px-3 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
              statusFilter === tab.value
                ? "bg-primary text-primary-foreground"
                : "bg-muted text-muted-foreground hover:bg-border"
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {mockTickets.length === 0 ? (
        <EmptyState
          icon={Ticket}
          title="暂无工单"
          description="你还没有提交过任何工单，可以去申领设备或发起报修。"
          actionLabel="申领设备"
          actionHref="/apply"
        />
      ) : (
        <div className="space-y-3">
          {filtered.map((ticket) => (
            <Link key={ticket.id} href={`/tickets/${ticket.id}`}>
              <Card className="hover:shadow-md transition-shadow">
                <CardContent className="p-4 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-lg bg-muted flex items-center justify-center">
                      <Ticket className="w-5 h-5 text-muted-foreground" />
                    </div>
                    <div>
                      <p className="font-medium">{ticket.title}</p>
                      <div className="flex items-center gap-2 mt-0.5">
                        <span className="text-xs text-muted-foreground">{ticket.id}</span>
                        <Badge variant={statusVariants[ticket.status]}>
                          {statusLabels[ticket.status]}
                        </Badge>
                        <span className="text-xs text-muted-foreground">{typeLabels[ticket.type]}</span>
                      </div>
                    </div>
                  </div>
                  <span className="text-xs text-muted-foreground">{ticket.createdAt}</span>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

/**
 * AI 助手对话 (所有角色)
 * 功能说明: 对话界面，用户可查询资产、保修、工单信息，或引导报修/申领
 * 交互: 输入消息 → AI 回复; 如需确认操作则显示确认对话框
 */

import { useState, useRef, useEffect } from "react";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Bot, Send, User, AlertTriangle } from "lucide-react";

interface Message {
  role: "user" | "assistant";
  content: string;
  action?: {
    type: "confirm_required";
    token: string;
    description: string;
  };
}

export default function ChatPage() {
  const [messages, setMessages] = useState<Message[]>([
    { role: "assistant", content: "你好！我是 IT 资产助手，可以帮你查询资产信息、保修状态、工单进度，也可以引导你进行设备申领或报修。请问有什么可以帮你的？" },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [confirmDialog, setConfirmDialog] = useState<{ open: boolean; token: string; description: string }>({
    open: false,
    token: "",
    description: "",
  });
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;
    const userMessage = input.trim();
    setInput("");
    setMessages((prev) => [...prev, { role: "user", content: userMessage }]);
    setIsLoading(true);

    // Simulate AI response
    setTimeout(() => {
      const simulatedResponse: Message = {
        role: "assistant",
        content: "根据你的请求，我查到你的当前持有设备：ThinkPad X1 Carbon (SN: XC12345678)，保修到期日 2028-03-15。请问你是想报修这台设备吗？",
        action: {
          type: "confirm_required",
          token: "mock-token-123",
          description: "创建报修工单 - ThinkPad X1 Carbon",
        },
      };
      setMessages((prev) => [...prev, simulatedResponse]);
      setIsLoading(false);
    }, 1000);
  };

  const handleConfirm = () => {
    setConfirmDialog({ ...confirmDialog, open: false });
    setMessages((prev) => [
      ...prev,
      { role: "user", content: "确认" },
      { role: "assistant", content: "已为你创建报修工单，工单编号: TKT-20260511-003。IT 管理员将尽快处理。📋" },
    ]);
  };

  return (
    <div className="max-w-3xl mx-auto h-[calc(100vh-8rem)] flex flex-col">
      <div className="mb-4">
        <h1 className="text-2xl font-bold tracking-tight">AI 助手</h1>
        <p className="text-muted-foreground mt-1">智能 IT 资产助手，帮你查询和管理设备</p>
      </div>

      {/* Chat Messages */}
      <Card className="flex-1 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.map((msg, i) => (
            <div key={i} className={`flex gap-3 ${msg.role === "user" ? "justify-end" : ""}`}>
              {msg.role === "assistant" && (
                <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center flex-shrink-0">
                  <Bot className="w-4 h-4 text-primary-foreground" />
                </div>
              )}
              <div className={`max-w-[75%] ${msg.role === "user" ? "order-1" : ""}`}>
                <div
                  className={`p-3 rounded-xl text-sm ${
                    msg.role === "user"
                      ? "bg-primary text-primary-foreground rounded-tr-sm"
                      : "bg-muted rounded-tl-sm"
                  }`}
                >
                  {msg.content}
                </div>
                {msg.action && (
                  <div className="mt-2 flex gap-2">
                    <Button
                      size="sm"
                      onClick={() => setConfirmDialog({ open: true, token: msg.action!.token, description: msg.action!.description })}
                    >
                      确认 {msg.action.description}
                    </Button>
                  </div>
                )}
              </div>
              {msg.role === "user" && (
                <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center flex-shrink-0">
                  <User className="w-4 h-4 text-muted-foreground" />
                </div>
              )}
            </div>
          ))}
          {isLoading && (
            <div className="flex gap-3">
              <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center flex-shrink-0">
                <Bot className="w-4 h-4 text-primary-foreground" />
              </div>
              <div className="bg-muted p-3 rounded-xl rounded-tl-sm text-sm text-muted-foreground">
                <span className="inline-flex gap-1">
                  <span className="animate-bounce">.</span>
                  <span className="animate-bounce" style={{ animationDelay: "0.1s" }}>.</span>
                  <span className="animate-bounce" style={{ animationDelay: "0.2s" }}>.</span>
                </span>
              </div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Input area */}
        <div className="border-t p-4">
          <div className="flex gap-2">
            <Input
              placeholder="输入你的问题，如：我的保修信息、我要报修笔记本..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSend()}
              className="flex-1"
            />
            <Button onClick={handleSend} disabled={!input.trim() || isLoading}>
              <Send className="w-4 h-4" />
            </Button>
          </div>
          <p className="text-xs text-muted-foreground mt-2">
            提示：你可以查询资产信息、保修状态、工单进度，或让 AI 引导你完成报修/申领
          </p>
        </div>
      </Card>

      {/* Confirmation Dialog */}
      <Dialog open={confirmDialog.open} onOpenChange={(open) => setConfirmDialog({ ...confirmDialog, open })}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="w-5 h-5 text-warning" />
              确认操作
            </DialogTitle>
            <DialogDescription>
              即将执行以下操作：
            </DialogDescription>
          </DialogHeader>
          <div className="p-3 rounded-lg bg-muted text-sm">
            {confirmDialog.description}
          </div>
          <div className="flex justify-end gap-3 mt-4">
            <Button variant="outline" onClick={() => setConfirmDialog({ ...confirmDialog, open: false })}>
              取消
            </Button>
            <Button onClick={handleConfirm}>确认执行</Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

/**
 * 通知中心 (所有角色)
 * 功能说明: 已读/未读通知列表，支持标记已读
 */

import { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import EmptyState from "@/components/empty-state";
import { Bell, CheckCheck, ChevronRight } from "lucide-react";

interface Notification {
  id: string;
  type: string;
  title: string;
  body: string;
  read: boolean;
  createdAt: string;
}

const mockNotifications: Notification[] = [
  { id: "n1", type: "APPROVAL_REQUEST", title: "审批请求", body: "李主管 提交了一台 ThinkPad 的申领审批请求", read: false, createdAt: "2026-05-11 10:30" },
  { id: "n2", type: "APPROVAL_RESULT", title: "申领已通过", body: "你的 ThinkPad 申领已通过主管审批", read: false, createdAt: "2026-05-10 14:20" },
  { id: "n3", type: "PICKUP_READY", title: "设备待领取", body: "你申领的 ThinkPad X1 Carbon 已分配，请到 IT 处领取", read: false, createdAt: "2026-05-09 16:00" },
  { id: "n4", type: "REPAIR_UPDATE", title: "维修进度更新", body: "你提交的笔记本维修工单已被接单", read: true, createdAt: "2026-05-08 11:00" },
  { id: "n5", type: "WARRANTY_EXPIRY", title: "保修到期提醒", body: "你的显示器 Dell U2724D 将于 2026-06-01 到期", read: true, createdAt: "2026-05-01 09:00" },
];

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState(mockNotifications);

  const unreadCount = notifications.filter((n) => !n.read).length;

  const markAllAsRead = () => {
    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
  };

  const markAsRead = (id: string) => {
    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, read: true } : n))
    );
  };

  if (notifications.length === 0) {
    return (
      <div className="max-w-3xl mx-auto space-y-6">
        <h1 className="text-2xl font-bold tracking-tight">通知中心</h1>
        <EmptyState icon={Bell} title="暂无通知" description="当你收到审批请求、工单更新等通知时，将显示在这里。" />
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">通知中心</h1>
          <p className="text-muted-foreground mt-1">
            {unreadCount > 0 ? `你有 ${unreadCount} 条未读通知` : "所有通知已读"}
          </p>
        </div>
        {unreadCount > 0 && (
          <Button variant="outline" size="sm" onClick={markAllAsRead}>
            <CheckCheck className="w-4 h-4 mr-1" />
            全部标已读
          </Button>
        )}
      </div>

      <div className="space-y-2">
        {notifications.map((n) => (
          <Card
            key={n.id}
            className={`cursor-pointer transition-colors hover:shadow-sm ${
              !n.read ? "border-l-4 border-l-primary bg-secondary/50" : ""
            }`}
            onClick={() => markAsRead(n.id)}
          >
            <CardContent className="p-4 flex items-start justify-between gap-4">
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <span className="font-medium text-sm">{n.title}</span>
                  {!n.read && <Badge variant="blue">新</Badge>}
                </div>
                <p className="text-sm text-muted-foreground line-clamp-2">{n.body}</p>
                <p className="text-xs text-muted-foreground mt-1">{n.createdAt}</p>
              </div>
              <ChevronRight className="w-4 h-4 text-muted-foreground flex-shrink-0 mt-1" />
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}

